'use strict';

const loopController = require('../factory/loop-controller');

const { scoreAutoGeneratedPlanDescriptions } = loopController._internalForTests;

describe('auto-generated plan description tracking-task quality scoring', () => {
  it('passes a tracking task that records evidence and wires the work item into tracking', () => {
    const plan = [
      '# Tracking Plan',
      '',
      '**Source:** auto-generated from work_item #659',
      '**Tech Stack:** Node.js',
      '',
      '## Task 1: Record evidence and wire the work item into project tracking',
      '',
      '- [ ] **Step 1: Record project tracking evidence**',
      '',
      '    Record the evidence note in docs/tracking/state-trace-659.json. Acceptance criteria: the decision log entry must reference work item 659 and the resulting branch name.',
    ].join('\n');

    const score = scoreAutoGeneratedPlanDescriptions(plan);
    const task = score.tasks[0];

    expect(task.score).toBeGreaterThanOrEqual(score.threshold);
    expect(task.signals.estimated_scope).toBe(true);
    expect(task.signals.validation_steps).toBe(true);
    expect(task.passed).toBe(true);
    expect(score.blocked).toBe(false);
  });

  it('does not rescue a bare tracking heading without paths or success criteria', () => {
    const plan = [
      '# Bare Tracking Plan',
      '',
      '**Source:** auto-generated from work_item #659',
      '**Tech Stack:** Node.js',
      '',
      '## Task 1: Wire up tracking',
      '',
    ].join('\n');

    const score = scoreAutoGeneratedPlanDescriptions(plan);
    const task = score.tasks[0];

    expect(task.score).toBeLessThan(score.threshold);
    expect(task.missing_signals).toContain('explicit_file_paths');
    expect(task.missing_signals).toContain('success_criteria');
    expect(score.blocked).toBe(true);
  });

  it('does not apply the tracking carve-out when code-change vocabulary is present', () => {
    const plan = [
      '# Mixed Tracking Plan',
      '',
      '**Source:** auto-generated from work_item #659',
      '**Tech Stack:** Node.js',
      '',
      '## Task 1: Record evidence and implement the new retry loop',
      '',
      '- [ ] **Step 1: Record evidence for the retry-loop tracking entry**',
      '',
      '    Record evidence in server/factory/loop-controller.js for the project tracking summary. Acceptance criteria: the tracking entry must identify work item 659 and the retry-loop branch.',
    ].join('\n');

    const score = scoreAutoGeneratedPlanDescriptions(plan);
    const task = score.tasks[0];

    expect(task.signals.estimated_scope).toBe(false);
    expect(task.score).toBeLessThan(score.threshold);
    expect(score.blocked).toBe(true);
  });

  it('keeps the documentation-only carve-out for doc-only tasks', () => {
    const plan = [
      '# Doc Plan',
      '',
      '**Source:** auto-generated from work_item #659',
      '**Tech Stack:** Node.js',
      '',
      '## Task 1: Mark historical design notes as superseded',
      '',
      '- [ ] **Step 1: Add supersession notices**',
      '',
      '    Edit docs/plans/2026-02-24-pixellab-integration-design.md and docs/plans/2026-03-07-style-consistency-design.md. Acceptance criteria: both docs must show the supersession notice before original content and must identify the active decision record.',
    ].join('\n');

    const score = scoreAutoGeneratedPlanDescriptions(plan);
    const task = score.tasks[0];

    expect(task.score).toBeGreaterThanOrEqual(score.threshold);
    expect(task.signals.estimated_scope).toBe(true);
    expect(task.passed).toBe(true);
    expect(score.blocked).toBe(false);
  });

  it('still rejects a tracking support task with unqualified vague language', () => {
    const plan = [
      '# Vague Tracking Plan',
      '',
      '**Source:** auto-generated from work_item #659',
      '**Tech Stack:** Node.js',
      '',
      '## Task 1: Record evidence and wire the work item into project tracking',
      '',
      '- [ ] **Step 1: Close out project tracking**',
      '',
      '    Acceptance criteria: the tracking summary must identify work item 659 and the resulting branch name.',
      '',
      '    Update things as needed.',
    ].join('\n');

    const score = scoreAutoGeneratedPlanDescriptions(plan);
    const task = score.tasks[0];

    expect(task.signals.estimated_scope).toBe(true);
    expect(task.signals.validation_steps).toBe(true);
    expect(task.missing_signals).toContain('concrete_language');
    expect(task.score).toBeLessThan(score.threshold);
    expect(score.blocked).toBe(true);
  });
});
